<set-variable name="priority" value="@{
    var c = (Newtonsoft.Json.Linq.JObject)context.Variables["contract-obj"];
    var v = c["priority"]; return v != null ? v.Value() : 2;
}" />

<set-variable name="caller-monthly-quota" value="@{
    var c = (Newtonsoft.Json.Linq.JObject)context.Variables["contract-obj"];
    var v = c["monthlyQuota"]; return v != null ? v.Value() : (long)0;
}" />




<set-variable name="requestedModel" value="@{
    var queryDeployment = context.Request.Url.Query.GetValueOrDefault("deployment", "");
    if (!string.IsNullOrEmpty(queryDeployment)) { return queryDeployment; }
    var queryModel = context.Request.Url.Query.GetValueOrDefault("model", "");
    if (!string.IsNullOrEmpty(queryModel)) { return queryModel; }

    var segments = context.Request.Url.Path.Split('/');
    for (int i = 0; i < segments.Length - 1; i++) {
        if (segments[i] == "deployments" && i + 1 < segments.Length) {
            return segments[i + 1];
        }
    }
    try {
        var body = context.Request.Body.As(preserveContent: true);
        var model = body?["model"];
        if (model != null && !string.IsNullOrEmpty(model.ToString())) {
            return model.ToString();
        }
    } catch { }
    return "unknown";
}" />









